INSERT INTO blogs (title, excerpt, content, author, category, image_url) VALUES 
('Xu hướng thời trang 2026', 'Khám phá những phong cách dẫn đầu xu hướng năm nay.', 'Nội dung chi tiết về các bộ sưu tập mang tính đột phá trong năm 2026, kết hợp giữa yếu tố truyền thống và hiện đại.', 'Admin', 'Fashion', 'https://images.unsplash.com/photo-1445205170230-053b83016050?q=80&w=800'),
('Bí quyết chọn đồ công sở', 'Làm sao để luôn chuyên nghiệp và tự tin tại văn phòng.', 'Chia sẻ các mẹo phối đồ giúp bạn tôn lên vóc dáng nhưng vẫn giữ được sự lịch sự và sang trọng nơi công sở.', 'Trần Lầu', 'Tips', 'https://images.unsplash.com/photo-1483985988355-763728e1935b?q=80&w=800'),
('Phụ kiện không thể thiếu', 'Những món đồ nhỏ giúp nâng tầm bộ trang phục của bạn.', 'Từ túi xách, đồng hồ đến các món đồ trang sức nhỏ xinh - tất cả đều có thể tạo nên sự khác biệt cho phong cách của bạn.', 'Thùy Dương', 'Accessories', 'https://images.unsplash.com/photo-1523275335684-37898b6baf30?q=80&w=800');
